#include <stdio.h>

int next_fit(int memory_blocks[], int n, int process_size, int* last_allocated) {
 int i = (*last_allocated + 1) % n;
 while (i != *last_allocated) {
 if (memory_blocks[i] >= process_size) {
 *last_allocated = i;
 return i;
 }
 i = (i + 1) % n;
 }
 return -1;
}

int main() {
 int memory_blocks[] = {100, 50, 200, 150};
 int n = sizeof(memory_blocks) / sizeof(memory_blocks[0]);
 int process_size = 80;
 int last_allocated = -1;
 int index = next_fit(memory_blocks, n, process_size, &last_allocated);
 if (index != -1) {
 printf("Process allocated at block %d\n", index);
 } else {
 printf("No suitable block found\n");
 }
 return 0;
}
